// Obyekt yaradıram
const bag = { phone: "smartphone", key: "house", earphones: "wireless" };
for (let item in bag) {
  console.log("Əşya: " + item + ", Dəyər: " + bag[item]);
}
// nəticə:
// Əşya: phone, Dəyər: smartphone
// Əşya: key, Dəyər: house
// Əşya: earphones, Dəyər: wireless

// Başqa bir nümunə
const person = { name: "Aysel", age: 20, city: "Bakı" };
for (let key in person) {
  console.log(key + ": " + person[key]);
}
// nəticə:
// name: Aysel
// age: 20
// city: Bakı

// Prototip xüsusiyyətləri ilə nümunə
const obj = { name: "Kamran" };
Object.prototype.extra = "əlavə xüsusiyyət";
for (let key in obj) {
  if (obj.hasOwnProperty(key)) {
    console.log(key + ": " + obj[key]);
  }
}
// nəticə: name: Kamran (extra görünmür, çünki yalnız öz xüsusiyyətləri yoxlanılır)

// Müqayisə nümunəsi
const items = { a: "alma", b: "banan" };
for (let key in items) {
  console.log("for...in: " + key + " -> " + items[key]);
}
// nəticə: for...in: a -> alma, for...in: b -> banan

const array = ["alma", "banan"];
for (let item of array) {
  console.log("for...of: " + item);
}
// nəticə: for...of: alma, for...of: banan

