// Create an object
const bag = { phone: "smartphone", key: "house", earphones: "wireless" };
for (let item in bag) {
  console.log("Item: " + item + ", Value: " + bag[item]);
}
// Output:
// Item: phone, Value: smartphone
// Item: key, Value: house
// Item: earphones, Value: wireless

// Another example
const person = { name: "Aysel", age: 20, city: "Baku" };
for (let key in person) {
  console.log(key + ": " + person[key]);
}
// Output:
// name: Aysel
// age: 20
// city: Baku

// Example with prototype properties
const obj = { name: "Kamran" };
Object.prototype.extra = "extra property";
for (let key in obj) {
  if (obj.hasOwnProperty(key)) {
    console.log(key + ": " + obj[key]);
  }
}
// Output: name: Kamran (extra is skipped because it’s not an own property)

// Comparison example
const items = { a: "apple", b: "banana" };
for (let key in items) {
  console.log("for...in: " + key + " -> " + items[key]);
}
// Output: for...in: a -> apple, for...in: b -> banana

const array = ["apple", "banana"];
for (let item of array) {
  console.log("for...of: " + item);
}
// Output: for...of: apple, for...of: banana

