// Создаём объект
const bag = { phone: "смартфон", key: "дом", earphones: "беспроводные" };
for (let item in bag) {
  console.log("Вещь: " + item + ", Значение: " + bag[item]);
}
// Вывод:
// Вещь: phone, Значение: смартфон
// Вещь: key, Значение: дом
// Вещь: earphones, Значение: беспроводные

// Ещё один пример
const person = { name: "Айсель", age: 20, city: "Баку" };
for (let key in person) {
  console.log(key + ": " + person[key]);
}
// Вывод:
// name: Айсель
// age: 20
// city: Баку

// Пример с прототипными свойствами
const obj = { name: "Кямран" };
Object.prototype.extra = "дополнительное свойство";
for (let key in obj) {
  if (obj.hasOwnProperty(key)) {
    console.log(key + ": " + obj[key]);
  }
}
// Вывод: name: Кямран (extra не отображается, так как это не собственное свойство)

// Пример сравнения
const items = { a: "яблоко", b: "банан" };
for (let key in items) {
  console.log("for...in: " + key + " -> " + items[key]);
}
// Вывод: for...in: a -> яблоко, for...in: b -> банан

const array = ["яблоко", "банан"];
for (let item of array) {
  console.log("for...of: " + item);
}
// Вывод: for...of: яблоко, for...of: банан

